import 'package:http/http.dart' as http;
import 'dart:convert';

class ApiClient {
  final String baseUrl = "https://api.example.com";
  final http.Client client;
  
  // Constructor to initialize the HTTP Client
  ApiClient({this.client}) : this.client = client ?? http.Client();
  
  Future<User> getUserProfile(String token) async {
    var url = Uri.parse("$baseUrl/user");
    
    // Adding headers for authentication
    var response = await client.get(url, headers: {"Authorization": "Bearer $token"});
    
    if (response.statusCode == 200) {
      return User.fromJson(jsonDecode(response.body));
    } else {
      throw Exception('Failed to load user profile');
    }
  }
  
  Future<void> syncData() async {
    var url = Uri.parse("$baseUrl/sync");
    
    // Sending a POST request for data synchronization
    var response = await client.post(url);
    
    if (response.statusCode == 200) {
      print('Data synced successfully');
    } else {
      throw Exception('Failed to sync data');
    }
  }
  
  Future<String> loginUser(String username, String password) async {
    var url = Uri.parse("$baseUrl/auth");
    
    // Sending a POST request for user authentication and receiving the token
    var response = await client.post(url, body: jsonEncode({"username": username, "password": password}));
    
    if (response.statusCode == 200) {
      return jsonDecode(response.body)["token"];
    } else {
      throw Exception('Failed to login');
    }
  }
  
  // Method for closing the HTTP Client connection
  void close() {
    client.close();
  }
}

class User {
  final String name;
  final int age;
  
  User({this.name, this.age});
  
  factory User.fromJson(Map<String, dynamic> json) {
    return User(
      name: json["name"],
      age: json["age"],
    );
  }
}